import React, { useState } from 'react';
import { View, Button, Text, Alert } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as Crypto from 'expo-crypto';
import * as SecureStore from 'expo-secure-store';

const AUTH_CONFIG = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  revocationEndpoint: 'https://your-auth-server.com/oauth/revoke',
  clientId: 'mobile_app_client_123',
  redirectUri: AuthSession.makeRedirectUri({ useProxy: false }),
  scopes: ['read', 'write'],
};

const generateCodeChallenge = async (codeVerifier) => {
  const digest = await Crypto.digestStringAsync(
    Crypto.CryptoDigestAlgorithm.SHA256,
    codeVerifier
  );
  return digest
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
};

const generateCodeVerifier = () => {
  return Crypto.getRandomBytes(32)
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
};

export default function App() {
  const [accessToken, setAccessToken] = useState(null);
  const [user, setUser] = useState(null);

  const handleLogin = async () => {
    try {
      const codeVerifier = generateCodeVerifier();
      const codeChallenge = await generateCodeChallenge(codeVerifier);

      await SecureStore.setItemAsync('codeVerifier', codeVerifier);

      const authUrl = `${AUTH_CONFIG.authorizationEndpoint}?` +
        `response_type=code&` +
        `client_id=${encodeURIComponent(AUTH_CONFIG.clientId)}&` +
        `redirect_uri=${encodeURIComponent(AUTH_CONFIG.redirectUri)}&` +
        `scope=${encodeURIComponent(AUTH_CONFIG.scopes.join(' '))}&` +
        `code_challenge=${codeChallenge}&` +
        `code_challenge_method=S256&` +
        `state=${Crypto.getRandomBytes(16).toString('hex')}`;

      const result = await AuthSession.startAsync({ authUrl });

      if (result.type === 'success') {
        await exchangeCodeForToken(result.params.code);
      }
    } catch (error) {
      Alert.alert('Authentication Error', 'Failed to authenticate');
      console.error('Auth error:', error.message);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const codeVerifier = await SecureStore.getItemAsync('codeVerifier');
      
      const response = await fetch(AUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: AUTH_CONFIG.redirectUri,
          client_id: AUTH_CONFIG.clientId,
          code_verifier: codeVerifier,
        }).toString(),
      });

      if (!response.ok) {
        throw new Error('Token exchange failed');
      }

      const tokens = await response.json();
      
      await SecureStore.setItemAsync('accessToken', tokens.access_token);
      await SecureStore.setItemAsync('refreshToken', tokens.refresh_token);
      
      setAccessToken(tokens.access_token);
      await fetchUserProfile(tokens.access_token);
      
      await SecureStore.deleteItemAsync('codeVerifier');
    } catch (error) {
      Alert.alert('Token Error', 'Failed to obtain access token');
      console.error('Token exchange error:', error.message);
    }
  };

  const fetchUserProfile = async (token) => {
    try {
      const response = await fetch('https://your-api.com/user/profile', {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      if (!response.ok) {
        throw new Error('Failed to fetch user profile');
      }

      const userData = await response.json();
      setUser(userData);
    } catch (error) {
      console.error('Profile fetch error:', error.message);
    }
  };

  const handleLogout = async () => {
    try {
      const token = await SecureStore.getItemAsync('accessToken');
      
      if (token) {
        await fetch(AUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: token,
            client_id: AUTH_CONFIG.clientId,
          }).toString(),
        });
      }

      await SecureStore.deleteItemAsync('accessToken');
      await SecureStore.deleteItemAsync('refreshToken');
      
      setAccessToken(null);
      setUser(null);
    } catch (error) {
      console.error('Logout error:', error.message);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', padding: 20 }}>
      {!accessToken ? (
        <Button title="Login with OAuth" onPress={handleLogin} />
      ) : (
        <View>
          <Text>Logged in as: {user?.email || 'User'}</Text>
          <Button title="Logout" onPress={handleLogout} />
        </View>
      )}
    </View>
  );
}